{"file_text": "export function initScrollWatcher(container, dotNetRef) {
    if (!container) return;

    let throttled = false;

    container.addEventListener('scroll', () => {
        if (throttled) return;
        if (container.scrollTop < 50) {
            throttled = true;
            dotNetRef.invokeMethodAsync('OnScrolledToTop').finally(() => {
                setTimeout(() => { throttled = false; }, 500);
            });
        }
    });
}

export function scrollToBottom(container) {
    if (container) {
        container.scrollTop = container.scrollHeight;
    }
}
