@inject IJSRuntime JS

<div class="message-list" @ref="scrollContainer">
    @if (HasMore)
    {
        <div data-scroll-sentinel class="scroll-sentinel">
            @if (loadingMore)
            {
                <span class="loading-indicator">Loading older messages...</span>
            }
        </div>
    }

