toolArgs.file_text:
.thread-panel {
    width: 25%;
    min-width: 280px;
    max-width: 400px;
    border-left: 1px solid #e0e0e0;
    background: #fff;
    display: flex;
    flex-direction: column;
    overflow: hidden;
}

.thread-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0.75rem 1rem;
    border-bottom: 1px solid #e0e0e0;
}

.thread-header h4 {
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
}

.close-btn {
    background: none;
    border: none;
    font-size: 1.1rem;
    cursor: pointer;
    color: #666;
    padding: 0.2rem 0.4rem;
    border-radius: 4px;
    transition: background 0.15s;
}

.close-btn:hover {
    background: #f0f0f0;
    color: #333;
}

.thread-root-message {
    padding: 0.75rem 1rem;
    background: #f7f7f7;
    border-bottom: 1px solid #e0e0e0;
    border-left: 3px solid #4a76a8;
}

.root-author {
    font-weight: 700;
    font-size: 0.9rem;
    margin-bottom: 0.2rem;
}

.root-content {
    font-size: 0.85rem;
    color: #444;
    white-space: pre-wrap;
    word-break: break-word;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 0.5rem 0;
}

.thread-reply {
    padding: 0.5rem 1rem;
}

.reply-header {
    display: flex;
    align-items: baseline;
    gap: 0.4rem;
    margin-bottom: 0.15rem;
}

.reply-author {
    font-weight: 700;
    font-size: 0.85rem;
    color: #1a1a1a;
}

.reply-timestamp {
    font-size: 0.7rem;
    color: #999;
}

.reply-content {
    font-size: 0.85rem;
    line-height: 1.4;
    color: #333;
    white-space: pre-wrap;
    word-break: break-word;
}

