+                 OnReplyClicked="OpenThread"
+                 OnReactionAdded="AddReaction" />
+
+    @if (isThreadOpen && threadRootMessage is not null)
+    {
+        <ThreadPanel RootMessage="threadRootMessage"
+                     ThreadMessages="threadMessages"
+                     OnClose="CloseThread"
+                     OnReplySent="SendThreadReply" />
+    }
+</div>
+
+@code {
+    private List<Channel> channels = [];
+    private Channel? selectedChannel;
+    private List<Message> messages = [];
+    private Message? threadRootMessage;
+    private List<Message> threadMessages = [];
+    private Dictionary<int, int> threadReplyCounts = [];
+    private bool isThreadOpen;
+    private bool hasMoreMessages;
+    private const int PageSize = 50;
+
+    protected override async Task OnInitializedAsync()
+    {
+        channels = await ChatService.GetChannelsAsync();
+        if (channels.Count > 0)
+        {
+            await SelectChannel(channels[0].Id);
+        }
+    }
+
+    private async Task SelectChannel(int channelId)
+    {
+        selectedChannel = channels.FirstOrDefault(c => c.Id == channelId);
+        if (selectedChannel is null) return;
+
+        messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
+        hasMoreMessages = messages.Count >= PageSize;
+        ComputeThreadReplyCounts();
+        CloseThread();
+
+        await ChatService.MarkChannelReadAsync(channelId);
+
+        var idx = channels.FindIndex(c => c.Id == channelId);
+        if (idx >= 0)
+        {
+            channels[idx] = selectedChannel with { UnreadCount = 0 };
+            selectedChannel = channels[idx];
+        }
+    }
+
+    private async Task LoadMoreMessages()
+    {
+        if (selectedChannel is null) return;
+
+        var older = await ChatService.GetMessagesAsync(selectedChannel.Id, messages.Count, PageSize);
+        hasMoreMessages = older.Count >= PageSize;
+        messages.InsertRange(0, older);
+        ComputeThreadReplyCounts();
+    }
+
+    private async Task SendMessage(string content)
+    {
+        if (selectedChannel is null) return;
+        var msg = await ChatService.SendMessageAsync(selectedChannel.Id, content, null);
+        messages.Add(msg);
+    }
+
+    private async Task OpenThread(int messageId)
+    {
+        threadRootMessage = messages.FirstOrDefault(m => m.Id == messageId);
+        if (threadRootMessage is null) return;
+
+        threadMessages = await ChatService.GetThreadAsync(messageId);
+        isThreadOpen = true;
+    }
+
+    private void CloseThread()
+    {
+        isThreadOpen = false;
+        threadRootMessage = null;
+        threadMessages = [];
+    }
+
+    private async Task SendThreadReply(string content)
+    {
+        if (selectedChannel is null || threadRootMessage is null) return;
+
+        var reply = await ChatService.SendMessageAsync(
+            selectedChannel.Id, content, threadRootMessage.Id);
+        threadMessages.Add(reply);
+        ComputeThreadReplyCounts();
+    }
+
+    private async Task AddReaction((int MessageId, string Emoji) reaction)
+    {
+        await ChatService.AddReactionAsync(reaction.MessageId, reaction.Emoji);
+
+        if (selectedChannel is not null)
+        {
+            messages = await ChatService.GetMessagesAsync(
+                selectedChannel.Id, 0, messages.Count);
+            ComputeThreadReplyCounts();
+        }
+    }
+
+    private void ComputeThreadReplyCounts()
+    {
+        threadReplyCounts = messages
+            .Where(m => m.ReplyToId is not null)
+            .GroupBy(m => m.ReplyToId!.Value)
+            .ToDictionary(g => g.Key, g => g.Count());
+    }
+}
+

